#include <stdio.h>
#include <cuda_runtime.h>
#include <math.h>

#define BLOCK_SIZE_0 256
#define BLOCK_SIZE_1_X 16
#define BLOCK_SIZE_1_Y 16

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + t] * b_dev[t];
        }
    }
}

// Forward declarations of helper functions used in main
void InitPerRun(int size, float *m);
void ForwardSub(float *a, float *b, float *m, int size);
void PrintMat(float *ary, int size, int nrow, int ncol);
void PrintAry(float *ary, int ary_size);
void BackSub(float *a, float *b, float *finalVec, int size);

int main(int argc, char *argv[]) {
    int size = -1;
    char filename[200];
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    // Parse command line arguments (simplified)
    if (argc < 2) {
        printf("Usage: %s <matrix_file> [-s size] [-q] [-v] [-t] [-p platform] [-d device]\n", argv[0]);
        return 1;
    }
    // Assume first argument is filename
    snprintf(filename, sizeof(filename), "%s", argv[1]);

    // Read matrix size from file
    FILE *fp = fopen(filename, "r");
    if (!fp) {
        printf("Failed to open file %s\n", filename);
        return 1;
    }
    if (fscanf(fp, "%d", &size) != 1 || size < 1) {
        printf("Invalid matrix size\n");
        fclose(fp);
        return 1;
    }

    // Allocate host memory
    float *a = (float *)malloc(size * size * sizeof(float));
    float *b = (float *)malloc(size * sizeof(float));
    float *m = (float *)malloc(size * size * sizeof(float));
    float *finalVec = (float *)malloc(size * sizeof(float));

    if (!a || !b || !m || !finalVec) {
        printf("Memory allocation failed\n");
        fclose(fp);
        free(a); free(b); free(m); free(finalVec);
        return 1;
    }

    // Initialize matrix a and array b from file
    for (int i = 0; i < size; i++) {
        for (int j = 0; j < size; j++) {
            if (fscanf(fp, "%f", &a[i * size + j]) != 1) {
                printf("Error reading matrix data\n");
                fclose(fp);
                free(a); free(b); free(m); free(finalVec);
                return 1;
            }
        }
    }
    for (int i = 0; i < size; i++) {
        if (fscanf(fp, "%f", &b[i]) != 1) {
            printf("Error reading array b data\n");
            fclose(fp);
            free(a); free(b); free(m); free(finalVec);
            return 1;
        }
    }
    fclose(fp);

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);
        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    InitPerRun(size, m);

    ForwardSub(a, b, m, size);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

    return 0;
}

void InitPerRun(int size, float *m) {
    for (int i = 0; i < size * size; i++) {
        m[i] = 0.0f;
    }
}

void ForwardSub(float *a, float *b, float *m, int size) {
    float *a_dev, *b_dev, *m_dev;
    cudaError_t err;

    err = cudaMalloc((void **)&a_dev, size * size * sizeof(float));
    if (err != cudaSuccess) { printf("cudaMalloc a_dev failed\n"); exit(1); }
    err = cudaMalloc((void **)&b_dev, size * sizeof(float));
    if (err != cudaSuccess) { printf("cudaMalloc b_dev failed\n"); exit(1); }
    err = cudaMalloc((void **)&m_dev, size * size * sizeof(float));
    if (err != cudaSuccess) { printf("cudaMalloc m_dev failed\n"); exit(1); }

    err = cudaMemcpy(a_dev, a, size * size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { printf("cudaMemcpy a failed\n"); exit(1); }
    err = cudaMemcpy(b_dev, b, size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { printf("cudaMemcpy b failed\n"); exit(1); }
    err = cudaMemcpy(m_dev, m, size * size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { printf("cudaMemcpy m failed\n"); exit(1); }

    for (int t = 0; t < size - 1; t++) {
        int fan1_grid = (size - 1 - t + BLOCK_SIZE_0 - 1) / BLOCK_SIZE_0;
        Fan1<<<fan1_grid, BLOCK_SIZE_0>>>(m_dev, a_dev, b_dev, size, t);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            printf("Kernel Fan1 launch failed: %s\n", cudaGetErrorString(err));
            exit(1);
        }
        cudaDeviceSynchronize();

        dim3 fan2_block(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);
        int fan2_grid_x = (size - 1 - t + BLOCK_SIZE_1_X - 1) / BLOCK_SIZE_1_X;
        int fan2_grid_y = (size - t + BLOCK_SIZE_1_Y - 1) / BLOCK_SIZE_1_Y;
        dim3 fan2_grid(fan2_grid_x, fan2_grid_y);
        Fan2<<<fan2_grid, fan2_block>>>(m_dev, a_dev, b_dev, size, t);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            printf("Kernel Fan2 launch failed: %s\n", cudaGetErrorString(err));
            exit(1);
        }
        cudaDeviceSynchronize();
    }

    err = cudaMemcpy(a, a_dev, size * size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { printf("cudaMemcpy a back failed\n"); exit(1); }
    err = cudaMemcpy(b, b_dev, size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { printf("cudaMemcpy b back failed\n"); exit(1); }
    err = cudaMemcpy(m, m_dev, size * size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { printf("cudaMemcpy m back failed\n"); exit(1); }

    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    for (int i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (int j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] /= a[size * (size - i - 1) + (size - i - 1)];
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            printf("%8.2e ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        printf("%.2e ", ary[i]);
    }
    printf("\n\n");
}
